package com.jwebmp.plugins.fontawesome5pro;

import com.google.common.base.Strings;
import com.jwebmp.core.base.angular.client.services.interfaces.AnnotationUtils;
import com.jwebmp.core.base.html.Script;
import com.jwebmp.core.plugins.PluginInformation;
import com.jwebmp.core.services.IPage;
import com.jwebmp.core.services.IPageConfigurator;

/**
 * The 3 meta tags *must* come first in the head; any other head content must come *after* these tags
 * <p>
 * HTML5 shim and Respond.js for IE8 support of HTML5 elements and media queries WARNING: Respond.js doesn't work if you view the page via
 * file://
 */
@PluginInformation(pluginName = "Component Template",
        pluginDescription = "ComponentTemplate does only one thing: replace the browser's default scrollbar with a custom CSS-styled one without losing performances. Unlike some popular plugins, ComponentTemplate doesn't mimic scroll with Javascript, causing janks and strange scrolling behaviours... You keep the awesomeness of native scrolling...with a custom scrollbar!\n" +
                "ComponentTemplate does NOT implement a custom scroll behaviour. It keeps the native overflow: auto scroll and only replace the scrollbar visual appearance.",
        pluginUniqueName = "jwebmp-componenttemplate",
        pluginVersion = "5.1.0",
        pluginCategories = "componenttemplate,ui,web ui, framework",
        pluginSubtitle = "ComponentTemplate makes sidebar development faster and easier.",
        pluginSourceUrl = "https://github.com/Grsmto/componenttemplate",
        pluginWikiUrl = "https://github.com/GedMarc/JWebMP-FontAwesome5Pro/wiki",
        pluginGitUrl = "https://github.com/GedMarc/JWebMP-FontAwesome5Pro",
        pluginIconUrl = "bower_components/componenttemplate/componenttemplateicon.jpg",
        pluginIconImageUrl = "bower_components/componenttemplate/componenttemplatelogo.jpg",
        pluginOriginalHomepage = "https://github.com/Grsmto/componenttemplate",
        pluginDownloadUrl = "https://github.com/GedMarc/JWebMP-FontAwesome5Pro")

public class FontAwesome5ProPageConfigurator implements IPageConfigurator<FontAwesome5ProPageConfigurator>
{
    private static String proKey;

    /**
     * The Font Awesome Kit code for cloud-configured icons (including custom uploaded icons).
     * When set, a {@code <script src="https://kit.fontawesome.com/{kitCode}.js">} tag
     * will be added to the page head, and the individual SVG icon packages will not be
     * added as npm dependencies (the Kit script fetches icons from the cloud).
     */
    private static String kitCode = "";

    /**
     * The default page configurator for componenttemplate
     */
    public FontAwesome5ProPageConfigurator()
    {
        //Nothing Needed
    }

    /**
     * The 3 meta tags *must* come first in the head; any other head content must come *after* these tags
     * <p>
     * HTML5 shim and Respond.js for IE8 support of HTML5 elements and media queries WARNING: Respond.js doesn't work if you view the page
     * via file://
     *
     * @return
     */
    @Override
    public IPage<?> configure(IPage<?> page)
    {
        if (!Strings.isNullOrEmpty(kitCode))
        {
            page.getHead()
                .add(new Script<>("https://kit.fontawesome.com/" + kitCode + ".js")
                        .addAttribute("crossorigin", "anonymous"));
        }
        return page;
    }

    /**
     * When no Kit code is configured, dynamically adds the individual Font Awesome Pro
     * SVG icon package dependencies to the generated package.json.
     * When a Kit code IS configured, these are unnecessary — the Kit script fetches
     * all icons from the cloud.
     */
    @Override
    public IPage<?> configureAngular(IPage<?> page)
    {
        if (Strings.isNullOrEmpty(kitCode))
        {
            page.getBody().addConfiguration(
                    AnnotationUtils.getTsDependency("@fortawesome/pro-solid-svg-icons", "^7.2.0", "fontawesome-svg-solid", true));
            page.getBody().addConfiguration(
                    AnnotationUtils.getTsDependency("@fortawesome/pro-regular-svg-icons", "^7.2.0", "fontawesome-svg-regular"));
            page.getBody().addConfiguration(
                    AnnotationUtils.getTsDependency("@fortawesome/pro-light-svg-icons", "^7.2.0", "fontawesome-svg-light"));
            page.getBody().addConfiguration(
                    AnnotationUtils.getTsDependency("@fortawesome/pro-duotone-svg-icons", "^7.2.0", "fontawesome-svg-duotone"));
            page.getBody().addConfiguration(
                    AnnotationUtils.getTsDependency("@fortawesome/pro-thin-svg-icons", "^7.2.0", "fontawesome-svg-thin"));
        }
        return page;
    }

    @Override
    public boolean enabled()
    {
        return true;
    }

    @Override
    public Integer sortOrder()
    {
        return 50;
    }

    public static String getProKey()
    {
        return proKey;
    }

    public static void setProKey(String proKey)
    {
        FontAwesome5ProPageConfigurator.proKey = proKey;
    }

    public static String getKitCode()
    {
        return kitCode;
    }

    /**
     * Sets the Font Awesome Kit code. When set, the kit script tag will be
     * injected into the page head, enabling custom uploaded icons (fak prefix).
     *
     * @param kitCode the kit identifier, e.g. "cf4534f35c"
     */
    public static void setKitCode(String kitCode)
    {
        FontAwesome5ProPageConfigurator.kitCode = kitCode;
    }
}

